import pandas as pd
from pathlib import Path
from typing import Generator, Callable

def read_chunks(filepath: str, chunksize: int = 100_000) -> Generator[pd.DataFrame, None, None]:
    for chunk in pd.read_csv(filepath, chunksize=chunksize):
        yield chunk

def transform_chunk(chunks):
    for chunk in chunks:
        chunk['event_ts'] = pd.to_datetime(chunk['event_ts'], errors='coerce')
        chunk['event_date'] = chunk['event_ts'].dt.date
        chunk['hour'] = chunk['event_ts'].dt.hour
        yield chunk

def filter_chunk(chunks, predicate):
    for chunk in chunks:
        filtered = predicate(chunk)
        if len(filtered) > 0:
            yield filtered

def write_partitioned_parquet(chunks, output_dir, partition_col='event_date'):
    output_path = Path(output_dir)
    total_rows = 0
    partitions_written = set()
    for chunk in chunks:
        for partition_val, partition_df in chunk.groupby(partition_col):
            partition_dir = output_path / f"{partition_col}={partition_val}"
            partition_dir.mkdir(parents=True, exist_ok=True)
            partition_df.to_parquet(partition_dir / f"part_{total_rows}.parquet", index=False)
            partitions_written.add(str(partition_val))
        total_rows += len(chunk)
    return {'total_rows': total_rows, 'partitions': len(partitions_written)}

from typing import List, Dict, Any

def dedup_by_key(records: List[Dict[str, Any]], key: str) -> List[Dict[str, Any]]:
    """
    Remove duplicate records based on a key field, keeping the first
    occurrence and preserving original order.
    Time: O(n), Space: O(n) for the seen set
    """
    seen = set()
    result = []
    for record in records:
        val = record[key]
        if val not in seen:
            seen.add(val)
            result.append(record)
    return result

