# Variant: keep LAST occurrence instead of first
def dedup_keep_last(records: List[Dict[str, Any]], key: str) -> List[Dict[str, Any]]:
    """Keep the last occurrence of each key, preserving order of last seen."""
    last_seen = {}
    for i, record in enumerate(records):
        last_seen[record[key]] = (i, record)
    return [rec for _, rec in sorted(last_seen.values())]
